settings.customCss:
@import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&display=swap');

.mf-contact-split {
  --background: oklch(0.98 0.008 280);
  --foreground: oklch(0.22 0.05 280);
  --card: oklch(1 0 0);
  --card-foreground: oklch(0.22 0.05 280);
  --primary: oklch(0.55 0.18 280);
  --primary-foreground: oklch(0.98 0 0);
  --secondary: oklch(0.94 0.02 280);
  --muted: oklch(0.96 0.01 280);
  --muted-foreground: oklch(0.48 0.03 280);
  --accent: oklch(0.65 0.15 320);
  --border: oklch(0.90 0.01 280);
  --input: oklch(0.97 0.01 280);
  --ring: oklch(0.55 0.18 280);

  display: block !important;
  width: 100% !important;
  min-height: 100%;
  position: relative;
  overflow: hidden !important;
  color: var(--foreground);
  background: var(--background);
  font-family: 'Inter', system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif !important;
  box-sizing: border-box;
}
.mf-contact-split *,
.mf-contact-split *::before,
.mf-contact-split *::after {
  box-sizing: border-box;
}
.mf-contact-split * {
  font-family: inherit !important;
}

.mf-contact-split .mf-bg,
.mf-contact-split .mf-overlay {
  position: absolute;
  inset: 0;
  z-index: 0;
  pointer-events: none;
}
.mf-contact-split .mf-bg {
  background: var(--background);
}
.mf-contact-split .mf-overlay {
  background:
    linear-gradient(135deg, color-mix(in oklab, var(--primary) 5%, transparent) 0%, transparent 46%),
    linear-gradient(180deg, color-mix(in oklab, var(--card) 84%, transparent) 0%, transparent 100%);
}

.mf-contact-split .mf-content {
  position: relative;
  z-index: 1;
  width: 100%;
  padding: 20px 14px;
}
@media (min-width: 768px) {
  .mf-contact-split .mf-content {
    padding: 28px 18px;
  }
}
@media (min-width: 1024px) {
  .mf-contact-split .mf-content {
    padding: 34px 20px;
  }
}

.mf-contact-split .mf-split-grid {
  display: grid;
  grid-template-columns: minmax(0, 1fr);
  gap: 20px;
  width: min(100%, 1120px);
  margin: 0 auto;
  align-items: start;
}
@media (min-width: 992px) {
  .mf-contact-split .mf-split-grid {
    grid-template-columns: minmax(0, 1fr) minmax(0, 1fr);
    gap: 24px;
  }
}

.mf-contact-split.mf-map-left .mf-map-col { order: 0; }
.mf-contact-split.mf-map-left .mf-form-col { order: 1; }
.mf-contact-split.mf-map-right .mf-form-col { order: 0; }
.mf-contact-split.mf-map-right .mf-map-col { order: 1; }
@media (max-width: 991px) {
  .mf-contact-split .mf-form-col { order: 0 !important; }
  .mf-contact-split .mf-map-col { order: 1 !important; }
}

.mf-contact-split .mf-map-col {
  display: grid;
  gap: 14px;
  min-width: 0;
}
.mf-contact-split .mf-map-wrap {
  width: 100%;
  min-height: 340px;
  aspect-ratio: 4 / 3;
  overflow: hidden;
  border: 1px solid var(--border);
  border-radius: 8px;
  background: var(--muted);
  box-shadow: 0 16px 38px -24px rgba(15, 23, 42, .35);
}
.mf-contact-split .mf-map-iframe {
  display: block;
  width: 100%;
  height: 100%;
  min-height: 340px;
  border: 0;
}
@media (min-width: 992px) {
  .mf-contact-split .mf-map-wrap,
  .mf-contact-split .mf-map-iframe {
    min-height: 430px;
  }
}

.mf-contact-split .mf-contact-info {
  display: grid;
  gap: 6px;
  padding: 16px 18px;
  border: 1px solid var(--border);
  border-radius: 8px;
  background: color-mix(in oklab, var(--card) 94%, var(--primary) 6%);
  box-shadow: 0 12px 30px -26px rgba(15, 23, 42, .32);
}
.mf-contact-split .mf-contact-title {
  margin: 0 0 4px;
  color: var(--foreground);
  font-size: 1rem;
  font-weight: 700;
  line-height: 1.25;
}
.mf-contact-split .mf-contact-line {
  margin: 0;
  color: var(--muted-foreground);
  font-size: .9rem;
  line-height: 1.55;
}
.mf-contact-split .mf-contact-line strong {
  color: var(--foreground);
  font-weight: 650;
}
.mf-contact-split .mf-contact-address {
  white-space: pre-line;
}

.mf-contact-split .mf-form-col {
  min-width: 0;
}
.mf-contact-split .mf-card {
  display: block;
  overflow: hidden;
  height: auto;
  border: 1px solid var(--border) !important;
  border-radius: 8px !important;
  background: var(--card) !important;
  color: var(--card-foreground);
  box-shadow: 0 18px 45px -28px rgba(15, 23, 42, .42) !important;
}
.mf-contact-split .mf-header {
  padding: 22px 24px 18px;
  border-bottom: 1px solid var(--border);
  background: linear-gradient(180deg, color-mix(in oklab, var(--muted) 62%, transparent), transparent);
}
.mf-contact-split .mf-title {
  margin: 0 0 8px;
  color: var(--foreground);
  font-size: clamp(1.7rem, 2.2vw, 2.25rem);
  font-weight: 700;
  line-height: 1.12;
  letter-spacing: 0;
}
.mf-contact-split .mf-lead {
  max-width: 58ch;
  margin: 0;
  color: var(--muted-foreground);
  font-size: .96rem;
  line-height: 1.55;
}
.mf-contact-split .mf-section {
  padding: 20px 24px 18px;
}
.mf-contact-split .mf-section-label {
  margin: 0 0 14px;
  color: var(--muted-foreground);
  font-size: .72rem;
  font-weight: 700;
  line-height: 1.2;
  letter-spacing: .1em;
  text-transform: uppercase;
}

.mf-contact-split .mf-fields {
  display: grid;
  gap: 14px;
}
.mf-contact-split .mf-row,
.mf-contact-split .mf-field-group {
  min-width: 0;
  margin: 0 !important;
}
.mf-contact-split .mf-grid-2 {
  display: grid;
  grid-template-columns: minmax(0, 1fr);
  gap: 14px;
}
@media (min-width: 620px) {
  .mf-contact-split .mf-grid-2 {
    grid-template-columns: minmax(0, 1fr) minmax(0, 1fr);
  }
}
.mf-contact-split .mf-grid-options {
  align-items: start;
}

.mf-contact-split .mf-field-label,
.mf-contact-split label.mf-field-label {
  display: block !important;
  margin: 0 0 6px !important;
  color: var(--foreground) !important;
  font-size: .83rem !important;
  font-weight: 650 !important;
  line-height: 1.3 !important;
}
.mf-contact-split .mf-required,
.mf-contact-split .mf-field-label .mf-required {
  color: var(--accent) !important;
  font-weight: 700 !important;
}
.mf-contact-split input[type="text"],
.mf-contact-split input[type="email"],
.mf-contact-split input[type="tel"],
.mf-contact-split select,
.mf-contact-split textarea,
.mf-contact-split .mf-input,
.mf-contact-split .mf-select,
.mf-contact-split .mf-textarea {
  display: block !important;
  width: 100% !important;
  max-width: none !important;
  min-height: 42px !important;
  margin: 0 !important;
  padding: 10px 12px !important;
  color: var(--foreground) !important;
  background: var(--input) !important;
  border: 1px solid var(--border) !important;
  border-radius: 6px !important;
  box-shadow: none !important;
  outline: none !important;
  font-size: .92rem !important;
  line-height: 1.45 !important;
  transition: border-color .15s ease, box-shadow .15s ease, background .15s ease !important;
}
.mf-contact-split textarea,
.mf-contact-split .mf-textarea {
  min-height: 126px !important;
  resize: vertical;
}
.mf-contact-split input:focus,
.mf-contact-split select:focus,
.mf-contact-split textarea:focus,
.mf-contact-split .mf-input:focus,
.mf-contact-split .mf-select:focus,
.mf-contact-split .mf-textarea:focus {
  border-color: var(--primary) !important;
  background: var(--card) !important;
  box-shadow: 0 0 0 3px color-mix(in oklab, var(--primary) 16%, transparent) !important;
}
.mf-contact-split ::placeholder {
  color: color-mix(in oklab, var(--muted-foreground) 68%, transparent) !important;
  opacity: 1 !important;
}

.mf-contact-split .mf-option-group {
  display: grid !important;
  grid-template-columns: minmax(0, 1fr) !important;
  gap: 8px !important;
  margin: 0 !important;
  padding: 0 !important;
}
.mf-contact-split .mf-field-group[data-type="Radio"] .mf-option-group {
  grid-template-columns: repeat(2, minmax(0, 1fr)) !important;
}
.mf-contact-split .mf-option-item,
.mf-contact-split label.mf-option-item {
  display: flex !important;
  align-items: center !important;
  gap: 9px !important;
  min-height: 42px !important;
  width: 100% !important;
  margin: 0 !important;
  padding: 9px 11px !important;
  cursor: pointer;
  color: var(--foreground) !important;
  background: color-mix(in oklab, var(--muted) 72%, var(--card) 28%) !important;
  border: 1px solid var(--border) !important;
  border-radius: 6px !important;
}
.mf-contact-split .mf-option-item input[type="radio"],
.mf-contact-split .mf-option-item input[type="checkbox"] {
  flex: 0 0 auto !important;
  width: 16px !important;
  height: 16px !important;
  min-height: 16px !important;
  margin: 0 !important;
  padding: 0 !important;
  accent-color: var(--primary);
}
.mf-contact-split .mf-option-label {
  display: block !important;
  min-width: 0;
  color: var(--foreground) !important;
  font-size: .88rem !important;
  font-weight: 550 !important;
  line-height: 1.25 !important;
}
.mf-contact-split .mf-field-error:empty {
  display: none !important;
}

.mf-contact-split .mf-submit-wrap {
  padding: 0 24px 20px;
}
.mf-contact-split .mf-submit-wrap button,
.mf-contact-split .mf-submit-wrap input[type="submit"],
.mf-contact-split .mf-btn-submit {
  display: inline-flex !important;
  align-items: center;
  justify-content: center;
  width: 100% !important;
  min-height: 46px !important;
  padding: 12px 18px !important;
  color: var(--primary-foreground) !important;
  background: var(--primary) !important;
  border: 1px solid var(--primary) !important;
  border-radius: 6px !important;
  font-size: .96rem !important;
  font-weight: 700 !important;
  line-height: 1.2 !important;
  cursor: pointer;
  transition: filter .15s ease, transform .15s ease, box-shadow .15s ease !important;
}
.mf-contact-split .mf-submit-wrap button:hover,
.mf-contact-split .mf-submit-wrap input[type="submit"]:hover,
.mf-contact-split .mf-btn-submit:hover {
  filter: brightness(1.05);
  transform: translateY(-1px);
  box-shadow: 0 12px 24px -18px var(--primary);
}
.mf-contact-split .mf-footer {
  padding: 14px 24px 20px;
  border-top: 1px solid var(--border);
  text-align: center;
  background: color-mix(in oklab, var(--muted) 42%, transparent);
}
.mf-contact-split .mf-footer p {
  margin: 0;
  color: var(--muted-foreground);
  font-size: .84rem;
  line-height: 1.45;
}

@media (max-width: 575px) {
  .mf-contact-split .mf-header,
  .mf-contact-split .mf-section,
  .mf-contact-split .mf-submit-wrap,
  .mf-contact-split .mf-footer {
    padding-left: 18px;
    padding-right: 18px;
  }
  .mf-contact-split .mf-title {
    font-size: 1.55rem;
  }
  .mf-contact-split .mf-map-wrap,
  .mf-contact-split .mf-map-iframe {
    min-height: 300px;
  }
}

.mf-contact-split .mf-theme-ui {
  position: fixed;
  z-index: 9999;
}

/* Mobile host-container guard */
@media (max-width: 575px) {
  .mf-contact-split {
    width: min(100%, calc(100vw - 48px)) !important;
    max-width: calc(100vw - 48px) !important;
    margin-left: auto !important;
    margin-right: auto !important;
  }
  .mf-contact-split .mf-content {
    padding-left: 0 !important;
    padding-right: 0 !important;
  }
  .mf-contact-split .mf-split-grid,
  .mf-contact-split .mf-card,
  .mf-contact-split .mf-map-col,
  .mf-contact-split .mf-map-wrap,
  .mf-contact-split .mf-contact-info {
    width: 100% !important;
    max-width: 100% !important;
  }
}

